def getCurrentMonth():
    from datetime import datetime
    return datetime.now().strftime('%m')

def getCurrentDay():
    from datetime import datetime
    return datetime.now().strftime('%d')

def getPastYear(days_back):
    from datetime import datetime, timedelta
    past_date = datetime.now() - timedelta(days=days_back)
    return past_date.strftime('%Y')

def getPastMonth(days_back):
    from datetime import datetime, timedelta
    past_date = datetime.now() - timedelta(days=days_back)
    return past_date.strftime('%m')

def getPastDay(days_back):
    from datetime import datetime, timedelta
    past_date = datetime.now() - timedelta(days=days_back)
    return past_date.strftime('%d')

