    }

    public static function writeLogEntry($message, $AddBRs, $MakeArray) {
        $logFile = '/var/www/schoolsystem/student-progress.log';
        $formattedMessage = $AddBRs ? nl2br($message) : $message;
        if ($MakeArray) {
            return explode("\n", $formattedMessage);
        }
        file_put_contents($logFile, $message . "\n", FILE_APPEND);
        return $formattedMessage;
    }

