  # Copy localized setup scripts for Ugandan schools
  shutil.copy(ubuntu_templates_dir+'/scripts/setup_ug_schools.sh', ubuntu_scripts_dir+'/setup_school.sh');

  # Get school-specific configuration from environment
  school_name = os.getenv('UG_SCHOOL_NAME', 'Default Primary School');
  school_district = os.getenv('UG_SCHOOL_DISTRICT', 'Kampala');

  # Customize scripts with school information
  cmd = "sed -i -e 's/SCHOOL_NAME_PLACEHOLDER/" + school_name + "/g' -e 's/SCHOOL_DISTRICT_PLACEHOLDER/" + school_district + "/g' " + ubuntu_scripts_dir + "/setup_school.sh";
