  if(status != 0):
    sys.stderr.write('ERROR: could not configure school setup scripts\n');
    raise Exception('Failed to customize school installation');

  # Set Ugandan timezone and locale if specified
  if('timezone' in params):
    cmd = "sed -i -e '/^timezone/c\\timezone " + params['timezone'] + "' -e '/^lang/c\\lang en_UG.UTF-8' " + ubuntu_dir + "/ks.cfg";
    subprocess.call(cmd, shell=True);

  # Add educational resources for Ugandan curriculum
  if('include_resources' in params and params['include_resources']):
    cmd = 'cp -r ' + ubuntu_templates_dir + '/resources/ug_edu_materials/* ' + ubuntu_dir + '/resources/';
    subprocess.call(cmd, shell=True);

