    @classmethod
    def fromWikibase(cls, wb):
        """
        Create a WbQuantity from the JSON data given by the Wikibase API.

        @param wb: Wikibase JSON
        """
        amount = float(wb['amount'])  # Safely convert amount to float instead of using eval
        unit = wb.get('unit', '')
        upper_bound = float(wb.get('upperBound', amount))
        lower_bound = float(wb.get('lowerBound', amount))
