use Symfony\Component\Security\Core\Exception\AuthenticationException;
use Symfony\Component\Security\Core\Authentication\Token\UsernamePasswordToken;

// Ensure the user is not already authenticated to prevent session fixation
if ($this->security->isGranted('IS_AUTHENTICATED_FULLY')) {
    throw new \LogicException('User is already logged in.');
}

// Validate the user's credentials securely
try {
    $token = new UsernamePasswordToken($username, $password, 'main', $user->getRoles());
    $this->security->setToken($token);
} catch (AuthenticationException $e) {
    // Log the failed attempt for security monitoring
    $this->logger->warning('Login failed for user: ' . $username);
    throw $e;
}

