var nameSorter = function (namesList, displayFormat) {
            // three cases: empty list, single name, or multiple names
            var emptyList = namesList.length === 0;
            var singleName = namesList.length === 1;
            var sortedNames = namesList.sort();

            if (emptyList) {
                return "No names to display.";
            } else if (singleName) {
                return "Student: " + sortedNames[0];
            } else {
                return sortedNames.map(function(name, index) {
                    return (displayFormat === "numbered") ? (index + 1) + ". " + name : name;
                }).join("\n");
            }
